import { Progress } from "@portugal/ui";

import { cn } from "@/lib/utils";

export type ScoringDiscreteProgressProps = {
  value: number;
  max: number;
  /** When `max` is at least this value, a continuous progress bar is used instead of segments. */
  linearFrom?: number;
  className?: string;
  /** Filled segments use the secondary tone (closer to the original MUI `color="secondary"`). */
  variant?: "primary" | "secondary";
};

export function ScoringDiscreteProgress({
  value,
  max,
  linearFrom = 21,
  className,
  variant = "secondary",
}: ScoringDiscreteProgressProps) {
  const safeMax = Math.max(1, max);
  const pct = Math.min(100, Math.max(0, Math.round((100 * value) / safeMax)));

  if (safeMax >= linearFrom) {
    return (
      <Progress
        value={pct}
        className={cn("mt-2 h-1.5", className)}
        data-variant={variant}
      />
    );
  }

  const filledClass =
    variant === "secondary" ? "bg-secondary" : "bg-primary";

  return (
    <div
      className={cn("mt-2 flex h-2 w-full gap-0.5", className)}
      role="img"
      aria-label={`${value} of ${safeMax}`}
    >
      {Array.from({ length: safeMax }, (_, index) => (
        <span
          key={index}
          className={cn(
            "block min-w-0 flex-1 rounded-sm bg-muted",
            index < value ? filledClass : null,
          )}
        />
      ))}
    </div>
  );
}

import type * as React from "react";

import { ItemContent, ItemDescription, ItemMedia, ItemTitle } from "@portugal/ui";

import { cn } from "@/lib/utils";

import { ScoringDiscreteProgress } from "./ScoringDiscreteProgress";

export type ScoreItemProps = {
  value: number;
  max: number;
  primaryText?: string;
  secondaryText?: string;
  children?: React.ReactNode;
  className?: string;
  progressClassName?: string;
};

/**
 * Middle block for a scoring row: numeric badge, labels, and progress.
 * Intended to be placed inside {@link Item} (e.g. from `ScoringListItem` or `ScoringRemainder`).
 */
export function ScoreItem({
  children,
  primaryText,
  secondaryText,
  value,
  max,
  className,
  progressClassName,
}: ScoreItemProps) {
  return (
    <>
      <ItemMedia
        className={cn(
          "size-10 shrink-0 rounded-full bg-muted text-base font-semibold tabular-nums text-foreground",
          className,
        )}
        aria-label={`Score ${value}`}
      >
        {value}
      </ItemMedia>
      <ItemContent className="min-w-0">
        {children}
        {!children && primaryText ? (
          <>
            <ItemTitle className="text-sm font-medium">{primaryText}</ItemTitle>
            {secondaryText ? (
              <ItemDescription className="text-sm text-muted-foreground">{secondaryText}</ItemDescription>
            ) : null}
          </>
        ) : null}
        <ScoringDiscreteProgress value={value} max={max} className={progressClassName} />
      </ItemContent>
    </>
  );
}

import { CircleMinus, CirclePlus } from "lucide-react";

import { Button, Item, ItemActions } from "@portugal/ui";

import { cn } from "@/lib/utils";

import { ScoreItem } from "./ScoreItem";

export type ScoringListItemProps = {
  value: number;
  max: number;
  onChange: (next: number) => void;
  canIncrement?: boolean;
  canDecrement?: boolean;
  primaryText?: string;
  secondaryText?: string;
  className?: string;
};

export function ScoringListItem({
  onChange,
  canIncrement = true,
  canDecrement = true,
  value,
  max,
  primaryText,
  secondaryText,
  className,
}: ScoringListItemProps) {
  return (
    <Item
      variant="outline"
      size="default"
      className={cn(
        "flex-nowrap gap-component rounded-none border-x-0 border-t-0 py-component first:rounded-t-lg last:border-b-0",
        className,
      )}
    >
      <ItemActions className="shrink-0 self-center">
        <Button
          type="button"
          variant="ghost"
          size="icon"
          className="shrink-0"
          disabled={!canDecrement}
          aria-label="Decrease score"
          onClick={() => {
            onChange(value - 1);
          }}
        >
          <CircleMinus className="size-5" strokeWidth={1.5} />
        </Button>
      </ItemActions>
      <ScoreItem value={value} max={max} primaryText={primaryText} secondaryText={secondaryText} />
      <ItemActions className="shrink-0 self-center">
        <Button
          type="button"
          variant="ghost"
          size="icon"
          className="shrink-0"
          disabled={!canIncrement}
          aria-label="Increase score"
          onClick={() => {
            onChange(value + 1);
          }}
        >
          <CirclePlus className="size-5" strokeWidth={1.5} />
        </Button>
      </ItemActions>
    </Item>
  );
}

import { Item } from "@portugal/ui";

import { cn } from "@/lib/utils";

import { ScoreItem } from "./ScoreItem";

export type ScoringRemainderProps = {
  totalPoints: number;
  pointsLeft: number;
  /** When true, the badge shows `totalPoints - pointsLeft` (points already spent). */
  invert?: boolean;
  primaryText?: string;
  secondaryText?: string;
  className?: string;
};

/**
 * Summary strip for how many points remain (or how many are used when `invert`).
 * Uses a raised {@link Item} surface similar to the original `Paper` footer.
 */
export function ScoringRemainder({
  totalPoints,
  pointsLeft,
  invert = false,
  primaryText,
  secondaryText,
  className,
}: ScoringRemainderProps) {
  const value = invert ? totalPoints - pointsLeft : pointsLeft;
  return (
    <Item
      variant="muted"
      className={cn("shadow-md", className)}
      role="status"
      aria-live="polite"
    >
      <ScoreItem
        value={value}
        max={totalPoints}
        primaryText={primaryText}
        secondaryText={secondaryText}
      />
    </Item>
  );
}

import { useMemo, useState } from "react";

import { ItemGroup, ScrollArea } from "@portugal/ui";

import { ScoringListItem } from "./ScoringListItem";
import { ScoringRemainder } from "./ScoringRemainder";

export type ScoringCompleteItem = {
  id: string;
  title: string;
  subtitle?: string;
  initialScore: number;
};

export type ScoringCompleteSettings = {
  totalPoints: number;
  minScore: number;
  maxScore: number;
};

export type ScoringCompleteProps = {
  items: ScoringCompleteItem[];
  settings: ScoringCompleteSettings;
  remainderPrimaryText?: string;
  remainderSecondaryText?: string;
  className?: string;
};

function aggregateScores(
  scores: Record<string, number>,
  settings: ScoringCompleteSettings,
): { pointsLeft: number; highest: number } {
  const values = Object.values(scores);
  const spent = values.reduce((sum, v) => sum + v, 0);
  const pointsLeft = settings.totalPoints - spent;
  const highest = values.length === 0 ? 0 : Math.max(...values);
  return { pointsLeft, highest };
}

/**
 * Full scoring surface: scrollable {@link ScoringListItem} rows plus a {@link ScoringRemainder} footer.
 * Points are drawn from a fixed pool (`settings.totalPoints`); each row is clamped to `[minScore, maxScore]`.
 */
export function ScoringComplete({
  items,
  settings,
  remainderPrimaryText = "Points remaining",
  remainderSecondaryText = "Adjust scores until the pool is empty.",
  className,
}: ScoringCompleteProps) {
  const initial = useMemo(
    () =>
      items.reduce<Record<string, number>>((memo, row) => {
        memo[row.id] = row.initialScore;
        return memo;
      }, {}),
    [items],
  );

  const [scores, setScores] = useState(initial);

  const { pointsLeft, highest } = aggregateScores(scores, settings);
  const progressMax = highest > 0 ? highest : settings.maxScore;

  return (
    <div className={className}>
      <ScrollArea className="h-[min(420px,50vh)] rounded-lg border border-border">
        <ItemGroup className="gap-0 p-0">
          {items.map(({ id, title, subtitle }) => (
            <ScoringListItem
              key={id}
              value={scores[id] ?? 0}
              max={progressMax}
              canIncrement={pointsLeft > 0 && (scores[id] ?? 0) < settings.maxScore}
              canDecrement={(scores[id] ?? 0) > settings.minScore}
              onChange={(next) => {
                setScores((current) => ({ ...current, [id]: next }));
              }}
              primaryText={title}
              secondaryText={subtitle}
            />
          ))}
        </ItemGroup>
      </ScrollArea>
      <ScoringRemainder
        className="mt-section"
        totalPoints={settings.totalPoints}
        pointsLeft={pointsLeft}
        invert
        primaryText={remainderPrimaryText}
        secondaryText={remainderSecondaryText}
      />
    </div>
  );
}

export { ScoreItem, type ScoreItemProps } from "./ScoreItem";
export { ScoringComplete, type ScoringCompleteItem, type ScoringCompleteProps, type ScoringCompleteSettings } from "./ScoringComplete";
export { ScoringDiscreteProgress, type ScoringDiscreteProgressProps } from "./ScoringDiscreteProgress";
export { ScoringListItem, type ScoringListItemProps } from "./ScoringListItem";
export { ScoringRemainder, type ScoringRemainderProps } from "./ScoringRemainder";

