import type { CriterionId, ProfileWeights } from "@portugal/domain-shared";
import { Button, ScrollArea, usePanelsContext } from "@portugal/ui";
import { ScoringListItem, ScoringRemainder } from "@portugal/ui-lib";
import { useCallback, useEffect, useMemo, useState } from "react";

import { useAuth } from "../hooks/use-auth";
import { type AppSnapshot, saveSnapshot } from "../lib/plot-storage";
import {
	MARBLE_TARGET,
	normalizeAllProfileWeightsToMarbleTarget,
	normalizeWeightsToSum,
	sumProfileWeights,
} from "../lib/profile-marbles";
import { groupCriteriaByCategory } from "../lib/scoring-config-mutations";
import { DetailPanelShell } from "./detail-panel-chrome";
import type { panelRegistry } from "./panel-registry";
import { PROFILE_EDIT_PANEL_TYPE } from "./panel-types";
import { usePanelSnapshot } from "./use-panel-snapshot";

type MutableWeights = Record<string, number>;

export type ProfileEditPanelProps = {
	panelType?: string;
	profileId?: string;
};

export function ProfileEditPanel({
	panelType = PROFILE_EDIT_PANEL_TYPE,
	profileId: profileIdProp,
}: ProfileEditPanelProps) {
	const profileId =
		typeof profileIdProp === "string" && profileIdProp.length > 0
			? profileIdProp
			: undefined;
	const { snapshot, loading, error } = usePanelSnapshot();
	const { removePanel } = usePanelsContext<typeof panelRegistry>();
	const { canManageData } = useAuth();
	const [draftWeights, setDraftWeights] = useState<MutableWeights>({});

	const profile = useMemo(
		() =>
			profileId && snapshot
				? snapshot.activeConfig.profiles.find((p) => p.id === profileId)
				: undefined,
		[profileId, snapshot],
	);

	const criterionIds = useMemo(
		() => snapshot?.activeConfig.criteria.map((c) => c.id) ?? [],
		[snapshot],
	);

	useEffect(() => {
		if (!profileId || !snapshot) {
			return;
		}
		const w = snapshot.activeConfig.profileWeights[profileId] ?? {};
		const filled: MutableWeights = {};
		for (const c of snapshot.activeConfig.criteria) {
			filled[c.id] = w[c.id] ?? 0;
		}
		const normalized = normalizeWeightsToSum(
			filled as ProfileWeights,
			criterionIds,
			MARBLE_TARGET,
		);
		setDraftWeights(normalized as MutableWeights);
	}, [profileId, snapshot, criterionIds]);

	const groupedCriteria = useMemo(
		() => (snapshot ? groupCriteriaByCategory(snapshot.activeConfig) : []),
		[snapshot],
	);

	const spent = useMemo(
		() => sumProfileWeights(draftWeights as ProfileWeights),
		[draftWeights],
	);

	const pointsLeft = MARBLE_TARGET - spent;

	const handleCancel = useCallback(() => {
		removePanel(panelType);
	}, [removePanel, panelType]);

	const handleSave = async () => {
		if (!snapshot || !profileId || !canManageData) {
			return;
		}
		const merged: AppSnapshot["activeConfig"]["profileWeights"] = {
			...snapshot.activeConfig.profileWeights,
			[profileId]: normalizeWeightsToSum(
				draftWeights as ProfileWeights,
				criterionIds,
				MARBLE_TARGET,
			),
		};
		const normalized = normalizeAllProfileWeightsToMarbleTarget({
			...snapshot.activeConfig,
			profileWeights: merged,
		});
		await saveSnapshot({
			...snapshot,
			activeConfig: {
				...snapshot.activeConfig,
				profileWeights: normalized,
			},
		});
	};

	const setCriterionWeight = useCallback((id: CriterionId, next: number) => {
		setDraftWeights((prev) => ({ ...prev, [id]: next }));
	}, []);

	if (!canManageData) {
		return (
			<DetailPanelShell title="Edit profile weights" panelType={panelType}>
				<p className="text-muted-foreground">You need data management access.</p>
				<Button type="button" variant="outline" size="sm" onClick={handleCancel}>
					Close
				</Button>
			</DetailPanelShell>
		);
	}

	if (loading) {
		return (
			<DetailPanelShell title="Edit profile weights" panelType={panelType}>
				<p className="text-muted-foreground">Loading…</p>
			</DetailPanelShell>
		);
	}

	if (error || !snapshot) {
		return (
			<DetailPanelShell title="Edit profile weights" panelType={panelType}>
				<p className="text-destructive">{error ?? "No data."}</p>
			</DetailPanelShell>
		);
	}

	if (!profileId) {
		return (
			<DetailPanelShell title="Edit profile weights" panelType={panelType}>
				<p className="text-muted-foreground">No profile selected.</p>
			</DetailPanelShell>
		);
	}

	if (!profile) {
		return (
			<DetailPanelShell title="Edit profile weights" panelType={panelType}>
				<p className="text-muted-foreground">
					No profile found for id <span className="font-mono">{profileId}</span>
					.
				</p>
			</DetailPanelShell>
		);
	}

	const title = `Edit weights · ${profile.name}`;

	return (
		<DetailPanelShell title={title} panelType={panelType}>
			<div className="flex flex-wrap gap-2">
				<Button type="button" variant="outline" size="sm" onClick={handleCancel}>
					Cancel
				</Button>
				<Button type="button" size="sm" onClick={() => void handleSave()}>
					Save & normalize marbles
