/**
 * Derives the discrete/linear progress scale from the current scores, with the same
 * ceiling idea as the complete scoring story: the scale max is at least `settingsMax`.
 * When every value is identical, the scale falls back to `[settingsMin, settingsMax]`
 * so the bar remains meaningful.
 */
export function resolveScoringProgressExtent(
  values: readonly number[],
  settingsMin: number,
  settingsMax: number,
): { min: number; max: number; mean: number } {
  if (values.length === 0) {
    const max = Math.max(settingsMax, settingsMin + 1);
    return { min: settingsMin, max, mean: settingsMin };
  }
  const sum = values.reduce((a, v) => a + (Number.isFinite(v) ? v : 0), 0);
  const mean = sum / values.length;
  const lowest = Math.min(...values);
  const highest = Math.max(...values);
  const equalAll = lowest === highest;
  if (equalAll) {
    const max = Math.max(settingsMax, settingsMin + 1);
    return { min: settingsMin, max, mean };
  }
  const min = lowest;
  const max = Math.max(highest, settingsMax);
  return { min, max, mean };
}

