export type ScoringDiscreteProgressProps = {
  value: number;
  max: number;
  /** When `max` is at least this value, a continuous progress bar is used instead of segments. */
  linearFrom?: number;
  className?: string;
  /** Filled segments use the secondary tone (closer to the original MUI `color="secondary"`). */
  variant?: "primary" | "secondary";
};

export function ScoringDiscreteProgress({
  value,
  max,
  linearFrom = 21,
  className,
  variant = "secondary",
}: ScoringDiscreteProgressProps) {
  const safeMax = Math.max(1, max);
  const pct = Math.min(100, Math.max(0, Math.round((100 * value) / safeMax)));

  if (safeMax >= linearFrom) {
    return (
      <Progress
        value={pct}
        className={cn(
          "mt-2 h-1.5",
          variant === "secondary" && "[&_[data-slot=progress-indicator]]:bg-secondary",
          className,
        )}
      />
    );
  }

  const filledClass = variant === "secondary" ? "bg-secondary" : "bg-primary";

  return (
    <div
      className={cn("mt-2 flex h-2 w-full gap-0.5", className)}
      role="img"
      aria-label={`${value} of ${safeMax}`}
    >
      {Array.from({ length: safeMax }, (_, index) => (
        <span
          key={index}
          className={cn(
            "block min-w-0 flex-1 rounded-sm bg-muted",
            index < value ? filledClass : null,
          )}
        />
      ))}
    </div>
  );
}

