export type ScoringDiscreteProgressProps = {
  value: number;
  max: number;
  /** Lower end of the scale (defaults to `0`). When set with `max`, fill reflects `(value - min) / (max - min)`. */
  min?: number;
  /** When `max - min` is at least this value, a continuous progress bar is used instead of segments. */
  linearFrom?: number;
  className?: string;
  /** Filled segments use the secondary tone (closer to the original MUI `color="secondary"`). */
  variant?: "primary" | "secondary";
};

export function ScoringDiscreteProgress({
  value,
  max,
  min = 0,
  linearFrom = 21,
  className,
  variant = "secondary",
}: ScoringDiscreteProgressProps) {
  const lo = Number.isFinite(min) ? min : 0;
  const hiRaw = Number.isFinite(max) ? max : lo + 1;
  const hi = hiRaw > lo ? hiRaw : lo + 1;
  const range = hi - lo;
  const position = Math.min(range, Math.max(0, value - lo));
  const pct = Math.min(100, Math.max(0, Math.round((100 * position) / range)));

  if (range >= linearFrom) {
    return (
      <Progress
        value={pct}
        className={cn(
          "mt-2 h-1.5",
          variant === "secondary" && "[&_[data-slot=progress-indicator]]:bg-secondary",
          className,
        )}
      />
    );
  }

  const filledClass = variant === "secondary" ? "bg-secondary" : "bg-primary";

  return (
    <div
      className={cn("mt-2 flex h-2 w-full gap-0.5", className)}
      role="img"
      aria-label={`${value} (${lo}–${hi})`}
    >
      {Array.from({ length: range }, (_, index) => (
        <span
          key={index}
          className={cn(
            "block min-w-0 flex-1 rounded-sm bg-muted",
            index < position ? filledClass : null,
          )}
        />
      ))}
    </div>
  );
}

