/**
 * Target average marbles per criterion when the pool is fully allocated:
 * `sum(weights) === criteria.length × MARBLE_AVG_PER_CRITERION`.
 */
export const MARBLE_AVG_PER_CRITERION = 5;

/** Total marble pool for a config with this many criteria (fully distributed → mean = {@link MARBLE_AVG_PER_CRITERION}). */
export function profileMarblePoolTotal(criterionCount: number): number {
	return Math.max(0, criterionCount) * MARBLE_AVG_PER_CRITERION;
