import type { CategoryId } from "@portugal/domain-shared";

function hashCategoryId(id: string): number {
  let h = 0;
  for (let i = 0; i < id.length; i += 1) {
    h = (h + id.charCodeAt(i) * (i + 1)) % 997;
  }
  return h;
}

const CHART_FALLBACK = [
  "bg-chart-1",
  "bg-chart-2",
  "bg-chart-3",
  "bg-chart-4",
  "bg-chart-5",
] as const;

const CHART_FILL_VAR_FALLBACK = [
  "var(--color-chart-1)",
  "var(--color-chart-2)",
  "var(--color-chart-3)",
  "var(--color-chart-4)",
  "var(--color-chart-5)",
] as const;

/**
 * Tailwind `bg-*` class for category-weight bars ({@link SegmentedProgress}) and similar.
 * Maps known {@link CategoryId} values to theme tokens; unknown ids use a stable chart fallback.
 */
export function categoryScoringBarClass(categoryId: string): string {
  switch (categoryId) {
    case "CAT_LOC":
      return "bg-category-loc";
    case "CAT_OMG":
      return "bg-category-omg";
    case "CAT_PER":
      return "bg-category-per";
    case "CAT_ONT":
      return "bg-category-ont";
    case "CAT_PRA":
      return "bg-category-pra";
    default: {
      const k = hashCategoryId(categoryId) % 5;
      return CHART_FALLBACK[k] ?? CHART_FALLBACK[0];
    }
  }
}

/**
 * Left accent for category group headers (`border-l-4` + color).
 */
export function categoryScoringLeadBorderClass(categoryId: string): string {
  switch (categoryId) {
    case "CAT_LOC":
      return "border-l-category-loc";
    case "CAT_OMG":
      return "border-l-category-omg";
    case "CAT_PER":
      return "border-l-category-per";
    case "CAT_ONT":
      return "border-l-category-ont";
    case "CAT_PRA":
      return "border-l-category-pra";
    default: {
      const k = hashCategoryId(categoryId) % 5;
      const borders = [
        "border-l-chart-1",
