import type { CSSProperties } from "react";

import { cn, Progress } from "@portugal/ui";

import { categoryScoringFillVarRef } from "../presentation/category-scoring-color";

export type ScoringDiscreteProgressProps = {
  value: number;
  /**
   * Progress cap for the whole set (same for every row). Typically the **current maximum score**
   * across rows so the leader shows 100% fill; when the global max moves, other rows rescale.
   */
  max: number;
  /**
   * Lower end of the scale (default `0`). Fill is `(value - min) / (max - min)`; list rows use the default.
   */
  min?: number;
  /** When `max - min` is at least this value, a continuous progress bar is used instead of segments. */
  linearFrom?: number;
  className?: string;
  /** Filled segments / bar when `categoryId` is not set. */
  variant?: "primary" | "secondary";
  /** When set, fill uses theme {@link categoryScoringFillVarRef} for this scoring category. */
  categoryId?: string;
};

export function ScoringDiscreteProgress({
  value,
  max,
  min = 0,
  linearFrom = 21,
  className,
  variant = "secondary",
  categoryId,
}: ScoringDiscreteProgressProps) {
  const lo = Number.isFinite(min) ? min : 0;
  const hiRaw = Number.isFinite(max) ? max : lo + 1;
  const hi = hiRaw > lo ? hiRaw : lo + 1;
  const range = hi - lo;
  const position = Math.min(range, Math.max(0, value - lo));
  const pct = Math.min(100, Math.max(0, Math.round((100 * position) / range)));

  const fillStyle: CSSProperties | undefined = categoryId
    ? { "--scoring-category-fill": categoryScoringFillVarRef(categoryId) }
    : undefined;

  const discreteFilledClass = categoryId
    ? "bg-[color:var(--scoring-category-fill)]"
    : variant === "secondary"
      ? "bg-secondary"
      : "bg-primary";

  const linearIndicatorClass = categoryId
    ? "[&_[data-slot=progress-indicator]]:bg-[color:var(--scoring-category-fill)]"
    : variant === "secondary"
      ? "[&_[data-slot=progress-indicator]]:bg-secondary"
      : "[&_[data-slot=progress-indicator]]:bg-primary";

  if (range >= linearFrom) {
    return (
      <div className={cn("mt-2", className)} style={fillStyle}>
        <Progress value={pct} className={cn("h-1.5", linearIndicatorClass)} />
      </div>
    );
  }

  return (
    <div
      className={cn("mt-2 flex h-2 w-full gap-0.5", className)}
      style={fillStyle}
      role="img"
      aria-label={`${value} of ${hi}`}
    >
      {Array.from({ length: range }, (_, index) => (
        <span
          key={index}
          className={cn(
            "block min-w-0 flex-1 rounded-sm bg-muted",
            index < position ? discreteFilledClass : null,
          )}
        />
      ))}
    </div>
  );
}

